    port = "5432",
    database = "myapp_db",
    user = "myapp_user",
    password = "myapp_password",
    socket_type = "nginx",  -- Use cosocket for OpenResty
})

-- Connect to PostgreSQL
local ok, err = pg:connect()
if not ok then
    ngx.status = 500
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error": "Database connection failed: ' .. (err or "unknown") .. '"}')
    return ngx.exit(500)
end

-- Build dynamic SQL query using string concatenation
